INSERT INTO reviews (name, role, text, rating) VALUES ('Анна', 'Собственник квартиры', 'После покупки квартиры в старом фонде перед началом капитального ремонта решили вызвать мастера для проверки систем вентиляции и их очистки. И это было невероятно правильным и своевременным решением! Мастер Даниил оперативно приехал, обследовал, показал все и обо всем рассказал. Каждый этап работы был понятен и оправдан. Работа выполнена быстро, аккуратно, качественно. Наглядно убедились в этом не только после визуальной оценки состояния вентканалов, но и замерили все прибором. Большая благодарность мастеру за человеческое отношение и за любовь к своему делу. Желаем успехов и процветания компании! Планируем обратиться за повторной чисткой после ремонта, а так же за периодическими поддерживающими чистками вентиляции, ведь это залог здоровья и безопасности в доме, особенно с газом!', 5);